def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    primes_cache = {}
    fib_cache = {}
    def is_prime(n):
        if n < 2:
            return False
        if n in primes_cache:
            return primes_cache[n]
        for x in range(2, int(n**0.5) + 1):
            if n % x == 0:
                primes_cache[n] = False
                return False
        primes_cache[n] = True
        return True
    def fib(n):
        if n in fib_cache:
            return fib_cache[n]
        if n == 0:
            fib_cache[0] = 0
            return 0
        elif n == 1:
            fib_cache[1] = 1
            return 1
        else:
            val = fib(n-1) + fib(n-2)
            fib_cache[n] = val
            return val
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf if item > cap else 1000
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.1:
            for a in range(1, 10):
                exp_decay = np.exp(-a*ratio*6)
                trig_component = np.cos(cap * a) + np.sin(ratio * a * 3)
                score += exp_decay * trig_component * (15 / (a + 1))
            prime_div_sum = 0
            for b in range(1, int(cap)+1):
                if cap % b == 0 and is_prime(b):
                    prime_div_sum += b ** 0.6
            score += prime_div_sum * 1.5
            if cap % 7 == 0:
                score *= 1.12
        elif 0.1 <= ratio < 0.35:
            poly_sum = 0
            for c in range(1, 7):
                poly_sum += ((-1)**(c+1)) * (ratio**c) * c**1.1
            harmonic_sum = 0
            for d in range(1, int(cap//3)+1):
                if cap % d == 0:
                    harmonic_sum += 1/d
            score += poly_sum * 10 + harmonic_sum * 7
            if cap % 8 == 0 or cap % 10 == 0:
                score *= 1.09
        elif 0.35 <= ratio <= 0.65:
            sine_wave = np.sin(ratio * np.pi * 7) * 15
            factorial_series = 0
            for e in range(1, 9):
                fact = 1
                for f in range(1, e+1):
                    fact *= f
                factorial_series += ((-1)**e) * (ratio**e) / fact
            score += sine_wave + factorial_series * 11
            for g in range(2, int(min(15, cap))):
                if cap % g == 0 and (g % 5 == 2 or g % 3 == 1):
                    score += np.sqrt(g) * 3.1
            fib_sum = 0
            limit = min(15, int(cap))
            for h in range(1, limit + 1):
                fib_val = fib(h)
                if fib_val != 0 and cap % fib_val == 0:
                    fib_sum += np.log1p(fib_val) * 2.5
            score += fib_sum
        elif 0.65 < ratio <= 0.9:
            logistic = 40 / (1 + np.exp(-30*(ratio - 0.8)))
            score += logistic
            for i in range(1, 15):
                if is_prime(i) and i % 4 == 3:
                    score += i * 1.1
            if ratio > 0.85:
                score += (1 - ratio) * 85
            if cap % 6 == 0 and ratio < 0.9:
                score *= 1.25
        elif 0.9 < ratio <= 1.2:
            penalty = 0
            chunk = max(1, int(cap//4))
            for j in range(1, chunk+1):
                if cap % j == 0:
                    penalty += j ** 1.9
            fract = ratio - int(ratio)
            for k in range(1, 10):
                mod_val = (fract * k * 1500) % 11
                penalty += (mod_val / 11) * 6
            score += penalty / (chunk + 3)
            score += (ratio - 1) * (-65)
            if cap % 13 == 0:
                score *= 0.92
            if int(cap) % 17 == 0:
                score += 18
        elif 1.2 < ratio <= 3:
            complex_sum = 0
            for l in range(1, int(min(20, cap))):
                if cap % l == 0:
                    if l % 3 == 0:
                        complex_sum += np.log1p(l) * 4
                    else:
                        complex_sum += np.sqrt(l) * 3
            fract_part = ratio - int(ratio)
            for m in range(1, 15):
                complex_sum += np.sin(fract_part * m * np.pi * 0.7) * 3
            score += complex_sum
            score += (ratio - 2) * 75
            if ratio > 2.5:
                for n in range(1, int(cap//2)+1):
                    if n % 5 == 0:
                        score += np.cos(n*1.5) * 5
        else:
            ultra_sum = 0
            limit_val = int(min(25, cap))
            for o in range(1, limit_val):
                if cap % o == 0:
                    if o % 4 == 0:
                        ultra_sum += np.log1p(o) * 5
                    elif o % 3 == 0:
                        ultra_sum += np.sqrt(o) * 4
                    else:
                        ultra_sum += (o ** 0.3) * 2
            fract_u = ratio - int(ratio)
            for p in range(1, 20):
                ultra_sum += np.cos(fract_u * p * np.pi / 2) * 3
            score += ultra_sum
            score += (ratio - 3) * 100
            if ratio > 5:
                for q in range(1, int(cap//4)+1):
                    if q % 11 == 0:
                        score += np.sin(q * 2) * 6
        if int(cap) % 3 == 0 and ratio < 2:
            score *= 1.11
        if int(cap) % 9 == 0 and ratio > 0.6:
            score *= 0.68
        if ratio > 4 and int(cap) % 8 == 0:
            score += 30
        if int(cap) % 20 == 0:
            score *= 0.79
        if ratio > 6:
            score += 50
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 500)
    return priorities
